    union() {
        // Hex head
        cylinder(d=hex_af / cos(30), h=hex_h, $fn=6);
        // Main body
        translate([0, 0, hex_h])
            cylinder(d=outer_d, h=height - hex_h - shoulder_h);
        // PCB locating shoulder
        translate([0, 0, height - shoulder_h])
            cylinder(d=shoulder_d, h=shoulder_h);
    }
    // Through-bore
    translate([0, 0, -1])
        cylinder(d=bore_d, h=height + 2);
}

