    cube([plate_w, thickness, plate_h]);
    // Mounting holes at 30, 60, 90mm
    for (z = [30, 60, 90]) {
        translate([plate_w/2, -1, z])
            rotate([-90, 0, 0])
            cylinder(d=mount_d, h=thickness+2);
    }
}

