difference() {
    translate([0, 0, plate_h - thickness])
        cube([plate_w, arm_l, thickness]);
    // Shelf screw holes at 30mm and 70mm from wall
    for (y = [30, 70]) {
        translate([plate_w/2, y, plate_h - thickness - 1])
            cylinder(d=shelf_hole_d, h=thickness+2);
    }
}

